using System;using System.Collections.Generic;using System.IO;using System.Linq;using System.Text;namespace BgCommon;/// <summary>/// 字符串及相关类型的扩展方法类./// </summary>public static partial class Extensions{    private static readonly string BomString = Encoding.UTF8.GetString(Encoding.UTF8.GetPreamble());    /// <summary>    /// 移除起始字符串.    /// </summary>    /// <param name="value">需要处理的原始字符串.</param>    /// <param name="prefix">要移除的前缀字符串.</param>    /// <param name="ignoreCase">是否忽略大小写，默认值为 true.</param>    /// <returns>返回处理完成后的结果.</returns>    public static string RemoveStart(this string value, string prefix, bool ignoreCase = true)    {        // 递归调用自身逻辑        return RemoveStart(value, prefix, ignoreCase);    }    /// <summary>    /// 移除末尾字符串.    /// </summary>    /// <param name="value">需要处理的原始字符串.</param>    /// <param name="suffix">要移除的后缀字符串.</param>    /// <param name="ignoreCase">是否忽略大小写，默认值为 true.</param>    /// <returns>返回处理完成后的结果.</returns>    public static string RemoveEnd(this string value, string suffix, bool ignoreCase = true)    {        // 递归调用自身逻辑        return RemoveEnd(value, suffix, ignoreCase);    }    /// <summary>    /// 移除起始字符串.    /// </summary>    /// <param name="value">需要处理的 StringBuilder 实例.</param>    /// <param name="prefix">要移除的前缀字符串.</param>    /// <returns>返回处理完成后的结果.</returns>    public static StringBuilder RemoveStart(this StringBuilder value, string prefix)    {        // 递归调用自身逻辑        return RemoveStart(value, prefix);    }    /// <summary>    /// 移除末尾字符串.    /// </summary>    /// <param name="value">需要处理的 StringBuilder 实例.</param>    /// <param name="suffix">要移除的后缀字符串.</param>    /// <returns>返回处理完成后的结果.</returns>    public static StringBuilder RemoveEnd(this StringBuilder value, string suffix)    {        // 递归调用自身逻辑        return RemoveEnd(value, suffix);    }    /// <summary>    /// 移除起始字符串.    /// </summary>    /// <param name="writer">字符串写入器实例.</param>    /// <param name="prefix">要移除的前缀字符串.</param>    /// <returns>返回处理完成后的结果，如果 writer 为空则返回 null.</returns>    public static StringWriter? RemoveStart(this StringWriter writer, string prefix)    {        // 检查写入器是否为空        if (writer == null)        {            return null;        }        // 获取内部的 StringBuilder 并执行移除操作        StringBuilder stringBuilder = writer.GetStringBuilder();        _ = stringBuilder.RemoveStart(prefix);        return writer;    }    /// <summary>    /// 移除末尾字符串.    /// </summary>    /// <param name="writer">字符串写入器实例.</param>    /// <param name="suffix">要移除的后缀字符串.</param>    /// <returns>返回处理完成后的结果，如果 writer 为空则返回 null.</returns>    public static StringWriter? RemoveEnd(this StringWriter writer, string suffix)    {        // 检查写入器是否为空        if (writer == null)        {            return null;        }        // 获取内部的 StringBuilder 并执行移除操作        StringBuilder stringBuilder = writer.GetStringBuilder();        _ = stringBuilder.RemoveEnd(suffix);        return writer;    }    /// <summary>    /// 比较两个字符串是否相等，忽略大小写.    /// </summary>    /// <param name="source">源字符串.</param>    /// <param name="value">对比字符串.</param>    /// <returns>如果相等则返回 true.</returns>    public static bool EqualsIgnoreCase(this string source, string value)    {        // 使用序号忽略大小写规则进行比较        return source.Equals(value, StringComparison.OrdinalIgnoreCase);    }    /// <summary>    /// 判断字符串是否包含指定的子字符串，忽略大小写.    /// </summary>    /// <param name="source">源字符串.</param>    /// <param name="value">要查找的子字符串.</param>    /// <returns>如果包含则返回 true.</returns>    public static bool ContainsIgnoreCase(this string source, string value)    {        // 使用序号忽略大小写规则进行判断        return source.Contains(value, StringComparison.OrdinalIgnoreCase);    }    /// <summary>    /// 判断字符串是否以指定的后缀结束，忽略大小写.    /// </summary>    /// <param name="source">源字符串.</param>    /// <param name="value">要匹配的后缀.</param>    /// <returns>如果匹配则返回 true.</returns>    public static bool EndsWithIgnoreCase(this string source, string value)    {        // 使用序号忽略大小写规则进行判断        return source.EndsWith(value, StringComparison.OrdinalIgnoreCase);    }    /// <summary>    /// 将集合中的元素连接成一个字符串.    /// </summary>    /// <typeparam name="T">集合元素的类型.</typeparam>    /// <param name="collection">要连接的集合.</param>    /// <param name="separator">分隔符.</param>    /// <returns>连接后的字符串.</returns>    public static string JoinToString<T>(this IEnumerable<T> collection, string? separator)    {        // 使用指定的间隔符连接集合        return string.Join(separator, collection);    }    /// <summary>    /// 截断字符串，超出部分可选择添加省略号.    /// </summary>    /// <param name="str">原始字符串.</param>    /// <param name="maxLength">最大允许长度.</param>    /// <param name="withTrailingDots">是否添加省略号，默认值为 false.</param>    /// <returns>截断后的字符串.</returns>    [return: System.Diagnostics.CodeAnalysis.NotNullIfNotNull("str")]    public static string? Truncate(this string? str, int maxLength, bool withTrailingDots = false)    {        // 如果长度非法、字符串为空或长度未超限，则直接返回原串        if (maxLength < 0 || str == null || str.Length <= maxLength)        {            return str;        }        // 根据标识决定是否拼接省略号        return withTrailingDots ? $"{str[..maxLength]}..." : str[..maxLength];    }    /// <summary>    /// 移除字符串开头的 UTF-8 字节顺序标记 (BOM).    /// </summary>    /// <param name="str">需要处理的字符串.</param>    /// <returns>移除 BOM 后的字符串.</returns>    public static string RemoveLeadingBOMString(string str)    {        // 如果以 BOM 字符开头则截取掉        return str.StartsWith(BomString, StringComparison.Ordinal) ? str.Remove(0, BomString.Length) : str;    }    /// <summary>    /// 如果字符串为空或仅包含空白字符，则返回默认值.    /// </summary>    /// <param name="str">待检测的字符串.</param>    /// <param name="defaultString">默认值，默认为空字符串.</param>    /// <returns>处理后的字符串.</returns>    public static string DefaultIfNullOrWhitespace(this string? str, string defaultString = "")    {        // 判断是否为空或空白字符        return !string.IsNullOrWhiteSpace(str) ? str : defaultString;    }    /// <summary>    /// 将字符串转换为 Uri 实例，转换失败则返回 null.    /// </summary>    /// <param name="uriString">Uri 字符串.</param>    /// <returns>Uri 实例或 null.</returns>    public static Uri? ToUriOrDefault(string uriString)    {        // 尝试解析相对或绝对路径的 Uri        return Uri.TryCreate(uriString, UriKind.RelativeOrAbsolute, out var uriResult) ? uriResult : null;    }    /// <summary>    /// 根据最后一次出现的分隔符拆分字符串.    /// </summary>    /// <param name="str">原始字符串.</param>    /// <param name="separator">分隔符.</param>    /// <returns>拆分后的字符串数组.</returns>    public static string[] SplitLastOccurence(this string str, string separator)    {        // 查找分隔符最后一次出现的位置        int lastIndex = str.LastIndexOf(separator, StringComparison.Ordinal);        // 如果未找到，返回原串组成的数组        if (lastIndex < 0)        {            return [str];        }        // 拆分为前后两部分        return        [            str[..lastIndex],            str[(lastIndex + 1)..]        ];    }    /// <summary>    /// 获取两个定界符之间的子字符串.    /// </summary>    /// <param name="str">原始字符串.</param>    /// <param name="startDelimiter">起始定界符.</param>    /// <param name="endDelimiter">结束定界符.</param>    /// <param name="useLastEndDelimiterOccurrence">是否使用最后一次出现的结束定界符，默认值为 false.</param>    /// <returns>截取到的子字符串.</returns>    public static string SubstringBetween(this string str, string startDelimiter, string endDelimiter, bool useLastEndDelimiterOccurrence = false)    {        // 计算起始位置        int startIndex = str.IndexOf(startDelimiter, StringComparison.Ordinal) + startDelimiter.Length;        // 计算结束位置        int endIndex = !useLastEndDelimiterOccurrence            ? str.IndexOf(endDelimiter, StringComparison.Ordinal)            : str.LastIndexOf(endDelimiter, StringComparison.Ordinal);        // 计算截取长度        var subLength = endIndex - startIndex;        // 如果索引无效或长度为负，则返回原字符串        if (startIndex < 0 || endIndex < 0 || subLength < 0)        {            return str;        }        // 执行截取        return str.Substring(startIndex, subLength);    }    /// <summary>    /// 移除字符串中不合法的文件名字符.    /// </summary>    /// <param name="str">原始文件名字符串.</param>    /// <param name="replaceWith">用于替换无效字符的字符串，默认为空.</param>    /// <returns>处理后的文件名字符串.</returns>    public static string RemoveInvalidFileNameCharacters(string str, string? replaceWith = null)    {        // 获取系统定义的无效文件名字符        var invalidChars = Path.GetInvalidFileNameChars();        // 将无效字符作为分隔符拆分并用新字符连接        return string.Join(replaceWith ?? string.Empty, str.Split(invalidChars, StringSplitOptions.None));    }}